	@Test
	void emitsTraceWhenEnabledAndRuntimeTelemetryEnabled() {
		TupleExpr tupleExpr = parseTupleExpr("SELECT * WHERE { ?s ?p ?o . ?o ?p2 ?x }");
		tupleExpr.setRuntimeTelemetryEnabled(true);

		UoeObserveOptimizer optimizer = new UoeObserveOptimizer(new UoeConfig(true, true));
		optimizer.optimize(tupleExpr, mock(Dataset.class), mock(BindingSet.class));

		String trace = tupleExpr.getStringMetricActual(UoeConfig.UOE_TRACE_METRIC_NAME);
		assertThat(trace).contains("\"uoeTrace\":{");
		assertThat(trace).contains("\"optimizerVersion\":\"uoe-observe-v1\"");
		assertThat(trace).contains("\"traceId\":\"");
		assertThat(trace).contains("\"config\":{");
		assertThat(trace).contains("\"enabled\":true");
		assertThat(trace).contains("\"observeTraceEnabled\":true");
		assertThat(trace).contains("\"events\":[{");
		assertThat(trace).contains("\"phase\":\"OBSERVE\"");
		assertThat(trace).contains("\"optimizer\":\"uoe-observe\"");
		assertThat(trace).contains("\"event\":\"PIPELINE_PASS\"");
		assertThat(trace).contains("\"joinCount\":1");
	}

	@Test
	void doesNotEmitTraceWhenDisabled() {
		TupleExpr tupleExpr = parseTupleExpr("SELECT * WHERE { ?s ?p ?o . ?o ?p2 ?x }");
		tupleExpr.setRuntimeTelemetryEnabled(true);

		UoeObserveOptimizer optimizer = new UoeObserveOptimizer(new UoeConfig(false, true));
		optimizer.optimize(tupleExpr, mock(Dataset.class), mock(BindingSet.class));

		assertThat(tupleExpr.getStringMetricActual(UoeConfig.UOE_TRACE_METRIC_NAME)).isNull();
	}

	@Test
	void standardPipelineIncludesUoeObserveOptimizer() {
		StandardQueryOptimizerPipeline pipeline = new StandardQueryOptimizerPipeline(
				mock(EvaluationStrategy.class),
				mock(TripleSource.class),
				new EvaluationStatistics());

		boolean present = StreamSupport.stream(pipeline.getOptimizers().spliterator(), false)
				.anyMatch(optimizer -> optimizer instanceof UoeObserveOptimizer);

		assertThat(present).isTrue();
	}

